"import { createClient } from '@supabase/supabase-js';
import dotenv from 'dotenv';
import path from 'path';

dotenv.config();

const supabaseUrl = process.env.VITE_SUPABASE_URL;
const supabaseKey = process.env.VITE_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseKey) {
    console.error("Missing Supabase credentials in .env file.");
    process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseKey);

async function checkDatabase() {
    console.log("Checking database connection and tables...");

    // Check daily_cash_operations
    const { count: opsCount, error: opsError } = await supabase
        .from('daily_cash_operations')
        .select('*', { count: 'exact', head: true });

    if (opsError) {
        console.error("Error querying daily_cash_operations:", opsError.message);
    } else {
        console.log(`Successfully verified daily_cash_operations! Count: ${opsCount}`);
    }

    // Check operating_expenses
    const { count: opexCount, error: opexError } = await supabase
        .from('operating_expenses')
        .select('*', { count: 'exact', head: true });

    if (opexError) {
        console.error("Error querying operating_expenses:", opexError.message);
    } else {
        console.log(`Successfully verified operating_expenses! Count: ${opexCount}`);
    }

    // Check fuel_prices
    const { count: priceCount, error: priceError } = await supabase
        .from('fuel_prices')
        .select('*', { count: 'exact', head: true });

    if (priceError) {
        console.error("Error querying fuel_prices:", priceError.message);
    } else {
        console.log(`Successfully verified fuel_prices! Count: ${priceCount}`);
    }
}

checkDatabase();
"

